//
//  WidgetLiveActivityManager.swift
//  Radiacode
//
//  Created by Matvey Kozin on 21.02.2024.
//

import Combine
import ActivityKit
import UIKit
import FactoryKit

final class WidgetLiveActivityManager {

    @Injected(\.deviceConnectionManager) private var deviceConnectionManager
    @Injected(\.signalizationViewModel) private var signalizationViewModel
    @Injected(\.appInfo) private var appInfo

    private var cancellable: Set<AnyCancellable> = .init()
    private var activityTask: Task<Void, Error>?
    private var shownRadiationType: RadiationType.Level = .doseRate
    private var startDate: Date?

    func prepareActivity() {
        guard !appInfo.isMacOS else { return }
        cancellable.removeAll()

        signalizationViewModel.publisher(\.showSignalizationAlarm)
            .dropFirst()
            .removeDuplicates()
            .sink { [weak self] value in
                guard let self = self else { return }
                self.activityTask?.cancel()
                activityTask = Task {
                   try await self.updateActivity(isAlarm: value)
                }
            }
            .store(in: &cancellable)

        deviceConnectionManager.connectionSubject
            .filter(\.isReady)
            .dropFirst()
            .delay(for: 5, scheduler: RunLoop.main)
            .sink { [weak self] _ in
                guard let self = self else { return }
                activityTask = Task {
                    try await self.updateActivity(isAlarm: false)
                }
            }
            .store(in: &cancellable)

        deviceConnectionManager.connectionSubject
            .filter(\.isReady)
            .first()
            .delay(for: 3, scheduler: RunLoop.main)
            .sink { [weak self] _ in
                guard let self = self else { return }
                Task {
                    await self.endActivity()
                    await self.startNewLiveActivity()
                }
            }
            .store(in: &cancellable)

        deviceConnectionManager.connectionSubject
            .dropFirst()
            .filter { !$0.isConnected }
            .receive(on: DispatchQueue.main)
            .sink { [weak self] value in
                guard let self = self else { return }
                if self.activityTask?.isCancelled == false {
                    self.stopLiveActivity()
                }
            }
            .store(in: &cancellable)

        NotificationCenter.default
            .publisher(for: .turnOffSignalization)
            .sink { [weak self] _ in
                guard let self = self else { return }
                Task {
                    await self.signalizationViewModel.turnOffSignalization()
                }
            }
            .store(in: &cancellable)

        NotificationCenter.default
            .publisher(for: UIApplication.willTerminateNotification)
            .sink { [weak self] _ in
                guard let self = self else { return }
                let semaphore = DispatchSemaphore(value: 0)
                Task {
                    await self.endActivity()
                    semaphore.signal()
                }
                semaphore.wait()
            }
            .store(in: &cancellable)
    }

    private func startNewLiveActivity() async {
        guard ActivityAuthorizationInfo().areActivitiesEnabled else { return }
        let attributes = RadiacodeWidgetExtensionAttributes()
        let contentState = getRadiationData()
        do {
            _ = try Activity<RadiacodeWidgetExtensionAttributes>.request(
                attributes: attributes,
                content: ActivityContent(state: contentState, staleDate: nil),
                pushType: .token
            )
            startDate = Date.now
            activityTask = Task {
                try await updateActivity(isAlarm: false)
            }
        } catch {
            Log.error(error)
        }
    }

    private func stopLiveActivity() {
        self.activityTask?.cancel()
        Task {
            await self.setActivity(data: .init(
                countRateModel: .init(value: nil, chartData: self.signalizationViewModel.countRateViewModel.averagingRawData.suffix(30).map { .init(count: $0.count, time: $0.time) }),
                doseRateModel: .init(value: nil, chartData: self.signalizationViewModel.doseRateViewModel.averagingRawData.suffix(30).map { .init(count: $0.count, time: $0.time)}),
                countRateLevel: .normal,
                doseRateLevel: .normal,
                activeRadiationType: .countRate,
                isReconnecting: true
            ))
        }
    }

    private func getRadiationData() -> RadiacodeWidgetExtensionAttributes.ContentState {
        .init(
            countRateModel: .init(
                value: signalizationViewModel.countRateViewModel.value,
                chartData: signalizationViewModel.countRateViewModel.averagingRawData.suffix(30).map { .init(count: $0.count, time: $0.time) }
            ),
            doseRateModel: .init(
                value: signalizationViewModel.doseRateViewModel.value,
                chartData: signalizationViewModel.doseRateViewModel.averagingRawData.suffix(30).map { .init(count: $0.count, time: $0.time) }
            ),
            signalizationTime: signalizationViewModel.signalizationTime,
            countRateLevel: signalizationViewModel.countRateViewModel.level,
            doseRateLevel: signalizationViewModel.doseRateViewModel.level,
            activeRadiationType: updateShownType(),
            isReconnecting: false
        )
    }

    private func updateShownType() -> RadiationType.Level {
        if signalizationViewModel.countRateViewModel.level == .normal && signalizationViewModel.doseRateViewModel.level != .normal {
            return .doseRate
        } else if signalizationViewModel.countRateViewModel.level != .normal && signalizationViewModel.doseRateViewModel.level == .normal {
            return .countRate
        } else {
            if shownRadiationType == .countRate {
                shownRadiationType = .doseRate
            } else {
                shownRadiationType = .countRate
            }
            return shownRadiationType
        }
    }

    private func updateActivity(isAlarm: Bool) async throws {
        if let startDate, Date.now.timeIntervalSince(startDate) > 7 * 3600  {
            stopLiveActivity()
            return
        }

        var alertConfig: AlertConfiguration? = nil
        if isAlarm {
            alertConfig = .init(title: "", body: "", sound: .default)
        }
        let data = getRadiationData()
        await setActivity(data: data, alertConfig: alertConfig)

        try await Task.sleep(seconds: signalizationViewModel.showSignalizationAlarm ? 3 : 30)
        try await updateActivity(isAlarm: false)
    }

    private func setActivity(data: RadiacodeWidgetExtensionAttributes.ContentState, alertConfig: AlertConfiguration? = nil) async {
        guard let runningActivity = Activity<RadiacodeWidgetExtensionAttributes>.activities.first else { return }
        await runningActivity.update(
            .init(
                state: data,
                staleDate: nil
            ),
            alertConfiguration: alertConfig
        )
    }

    private func endActivity() async {
        for activity in Activity<RadiacodeWidgetExtensionAttributes>.activities {
            await activity.end(nil, dismissalPolicy: .immediate)
        }
    }
}

