//
//  SignalizationViewModel.swift
//  RadiacodeWidgetExtension
//
//  Created by Matvey Kozin on 29.02.2024.
//

import Foundation
import Combine
import FactoryKit

@Observable
final class SignalizationViewModel {

    @ObservationIgnored
    @Injected(\.deviceManager) private var deviceManager
    @ObservationIgnored
    @Injected(\.deviceContainer) private var deviceContainer
    @ObservationIgnored
    @Injected(\.dataBufferRepository) private var dataBufferRepository
    @ObservationIgnored
    @LazyInjected(\.hapticManager) private var hapticManager

    var signalizationTime: Date? = nil
    var showSignalizationAlarm: Bool = false {
        didSet {
            if showSignalizationAlarm {
                hapticManager.play(pattern: .signalization)
            } else {
                hapticManager.stop()
            }
        }
    }

    var countRateViewModel: RadiationLevelViewModel
    var doseRateViewModel: RadiationLevelViewModel

    @ObservationIgnored
    private var cancellable: Set<AnyCancellable> = .init()

    init(countRateViewModel: RadiationLevelViewModel, doseRateViewModel: RadiationLevelViewModel) {
        self.countRateViewModel = countRateViewModel
        self.doseRateViewModel = doseRateViewModel

        dataBufferRepository.eventPublisher
            .filter (\.id.isAlarm)
            .filter { !$0.isOld }
            .receive(on: DispatchQueue.main)
            .sink { [weak self] event in
                guard let self = self, self.deviceContainer.current?.settings.alarm == true else { return }
                if !event.time.isActiveDate {
                    if self.countRateViewModel.level == .normal && self.doseRateViewModel.level == .normal {
                        return
                    }
                }

                if signalizationTime == nil {
                    signalizationTime = Date(timeIntervalSince1970: event.time)
                }
                if showSignalizationAlarm == false {
                    showSignalizationAlarm = true
                }
            }
            .store(in: &cancellable)
    }

    @MainActor
    func turnOffSignalization() async {
        await deviceManager.send(command: PlaySignalCommand(action: .stop))
        signalizationTime = nil
        showSignalizationAlarm = false
    }
}

//
//  RadiationLevelChartViewModel.swift
//  Radiacode
//
//  Created by Matvey Kozin on 23.01.2024.
//

import Foundation
import Combine

@Observable
final class RadiationLevelViewModel {

    enum Consts {
        static let rawDataMaxCount = 600
    }

    var averagingRawData: [RadiationLevelChartDataModel] = []
    var purifiedData: [RadiationLevelChartDataModel] = []

    var value: Float?
    var error: Float?
    var level: SignalizationAlarmLevel = .normal

    private let queue: DispatchQueue
    private let chartModelBuilder: ChartModelBuilder

    @ObservationIgnored
    private var fullRawData: [RadiationLevelChartDataModel] = []
    @ObservationIgnored
    private var cancellable: Set<AnyCancellable> = .init()

    init(
        chartModelBuilder: ChartModelBuilder,
        rawDataPublisher: AnyPublisher<DataBufferBatch, Never>,
        purifiedDataPublisher: AnyPublisher<DataBufferBatch, Never>,
        valuePublisher: AnyPublisher<RadiationData, Never>,
        initialDataPublisher: AnyPublisher<[DataBufferBatch], Never>,
        queueLabel: String
    ) {
        self.queue = DispatchQueue(label: "com.radiacode.\(queueLabel).buffer")
        self.chartModelBuilder = chartModelBuilder

        rawDataPublisher
            .map { RadiationLevelChartDataModel(count: $0.value, time: $0.time) }
            .receive(on: queue)
            .sink { [weak self] rawData in
                guard let self else { return }
                fullRawData.insertSorted(rawData)
                if fullRawData.count > Consts.rawDataMaxCount {
                    fullRawData.removeFirst(fullRawData.count - Consts.rawDataMaxCount)
                }
                let averagingData = chartModelBuilder.averagingRawData(rawData: fullRawData)
                Task { @MainActor in
                    self.averagingRawData = averagingData
                }
            }
            .store(in: &cancellable)

        purifiedDataPublisher
            .map { RadiationLevelChartDataModel(count: $0.value, time: $0.time) }
            .collect(.byTime(queue, 2))
            .receive(on: DispatchQueue.main)
            .sink { [weak self] data in
                guard let self else { return }
                purifiedData.append(contentsOf: data)
            }
            .store(in: &cancellable)

        valuePublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] data in
                guard let self else { return }
                self.value = data.value
                self.error = data.error
                self.level = data.level
            }
            .store(in: &cancellable)

        initialDataPublisher
            .map { $0.map { RadiationLevelChartDataModel(count: $0.value, time: $0.time) } }
            .receive(on: DispatchQueue.main)
            .sink { [weak self] purifiedData in
                guard let self else { return }
                /// Предварительно необходимо обнулить массив для очистки графика
                self.purifiedData = []
                Task {
                    await MainActor.run {
                        self.purifiedData = purifiedData
                        self.fullRawData = []
                        self.averagingRawData = []
                        self.value = nil
                        self.error = 0
                        self.level = .normal
                    }
                }
            }
            .store(in: &cancellable)
    }
}

