import DGCharts
import UIKit
import SwiftUI

extension LineChartView {

    enum Consts {
        static let rawDataSetLabel = "rawDataSet"
        static let purifiedDataSetLabel = "purifiedDataSet"
    }

    static func makeChartView(
        rawData: [RadiationLevelChartDataModel],
        purifiedData: [RadiationLevelChartDataModel],
        lineWidth: CGFloat,
        color: NSUIColor
    ) -> LineChartView {
        let chartView = LineChartView()
        let rawDataSet = TimeOrderedLineDataSet(label: Consts.rawDataSetLabel)
        rawDataSet.axisDependency = .right
        rawData.forEach { data in
            rawDataSet.addEntryOrdered(ChartDataEntry(x: data.time, y: Double(data.count)))
        }
        rawDataSet.setColor(NSUIColor(.light02))
        rawDataSet.lineWidth = lineWidth

        rawDataSet.drawCirclesEnabled = false
        rawDataSet.drawValuesEnabled = false
        rawDataSet.highlightEnabled = false
        rawDataSet.setDrawHighlightIndicators(false)

        let purifiedDataSet = TimeOrderedLineDataSet(label: Consts.purifiedDataSetLabel)
        purifiedDataSet.axisDependency = .right
        purifiedData.forEach { data in
            purifiedDataSet.addEntryOrdered(ChartDataEntry(x: data.time, y: Double(data.count)))
        }
        purifiedDataSet.setColor(color)
        purifiedDataSet.lineWidth = 1
        purifiedDataSet.fillAlpha = 0.25
        purifiedDataSet.fill = ColorFill(color: color)
        purifiedDataSet.drawFilledEnabled = true
        purifiedDataSet.drawCirclesEnabled = false
        purifiedDataSet.drawValuesEnabled = false
        purifiedDataSet.highlightEnabled = false
        purifiedDataSet.setDrawHighlightIndicators(false)

        let data = LineChartData(dataSets: [rawDataSet, purifiedDataSet])
        chartView.data = data

        chartView.dragYEnabled = false
        chartView.scaleYEnabled = false
        chartView.highlightPerDragEnabled = false
        chartView.doubleTapToZoomEnabled = false
        chartView.leftAxis.enabled = false
        chartView.legend.enabled = false
        chartView.autoScaleMinMaxEnabled = true
        chartView.minOffset = 0

        return chartView
    }

    static func makeRadiationLevelChart(
        rawData: [RadiationLevelChartDataModel],
        purifiedData: [RadiationLevelChartDataModel],
        timeRange: RadiationLevelOptions.TimeRange,
        scale: RadiationLevelOptions.Scale,
        color: NSUIColor,
        coordinator: RadiationLevelChartCoordinator,
        indexes: Binding<[Int]>,
        mainSourceForCalculating: Bool,
        radiationType: RadiationType.Level?
    ) -> LineChartView {
        let chartView = makeChartView(
            rawData: rawData,
            purifiedData: purifiedData,
            lineWidth: 1,
            color: color
        )
        chartView.delegate = coordinator

        chartView.pinchZoomEnabled = true
        chartView.dragXEnabled = true

        chartView.xAxis.labelTextColor = UIColor(.textSecondary)
        chartView.xAxis.labelPosition = .bottom
        chartView.xAxis.valueFormatter = DateAxisValueFormatter()
        chartView.xAxis.gridLineDashPhase = 4.0
        chartView.xAxis.gridLineDashLengths = [4.0]
        chartView.xAxis.axisLineColor = .clear
        chartView.xAxis.gridColor = UIColor(.separatorFill)
        chartView.xAxis.labelCount = 4
        chartView.xAxis.drawGridLinesBehindDataEnabled = true

        chartView.rightAxis.valueFormatter = PrecisionAxisValueFormatter(radiationType: radiationType)
        chartView.rightAxis.axisMinimum = 0

        chartView.rightAxis.axisLineColor = .clear
        chartView.rightAxis.labelTextColor = UIColor(.textSecondary)
        chartView.rightAxis.labelPosition = .insideChart
        chartView.rightAxis.labelXOffset = 32
        chartView.extraRightOffset = 32
        chartView.rightAxis.gridColor = UIColor(.separatorFill)

        chartView.renderer = RadiationLevelChartRenderer(
            dataProvider: chartView,
            animator: chartView.chartAnimator,
            viewPortHandler: chartView.viewPortHandler,
            indexes: indexes,
            mainSourceForCalculating: mainSourceForCalculating
        )

        chartView.legendRenderer = NoOpLegendRenderer(
            viewPortHandler: chartView.viewPortHandler,
            legend: chartView.legend
        )

        chartView.leftYAxisRenderer = NoOpYAxisRenderer(
            viewPortHandler: chartView.viewPortHandler,
            axis: chartView.leftAxis,
            transformer: chartView.getTransformer(forAxis: .left)
        )

        switch scale {
        case .initial:
            if let data = chartView.data {
                chartView.focusX(minXValue: data.xMax - timeRange.timeInterval, maxXValue: data.xMax)
            }
        case let .live(minX, maxX),
            let .position(minX, maxX):
            chartView.focusX(minXValue: minX, maxXValue: maxX)
        }

        Task { @MainActor in
            chartView.notifyDataSetChanged()
        }

        coordinator.cachedPurifiedData = purifiedData
        coordinator.cachedRawData = rawData
        coordinator.cachedTimeRange = timeRange
        coordinator.cachedScale = scale

        return chartView
    }

    @discardableResult
    func updateData(
        rawData: [RadiationLevelChartDataModel],
        purifiedData: [RadiationLevelChartDataModel],
        coordinator: RadiationLevelCoordinatorProtocol
    ) -> Bool {
        guard
            let rawDataSet = data?.dataSets.first(where: { $0.label == Consts.rawDataSetLabel }) as? LineChartDataSet,
            let purifiedDataSet = data?.dataSets.first(where: { $0.label == Consts.purifiedDataSetLabel }) as? LineChartDataSet
        else {
            return false
        }

        var changed = false

        if rawDataSet.count > RadiationLevelViewModel.Consts.rawDataMaxCount {
            rawDataSet.removeFirst(rawDataSet.count - RadiationLevelViewModel.Consts.rawDataMaxCount)
            changed = true
        }

        if rawData != coordinator.cachedRawData {
            if rawData.isEmpty {
                rawDataSet.removeAll(keepingCapacity: true)
            } else {
                let excludeArray = Set(coordinator.cachedRawData)
                let addedObjects = rawData.filter { !excludeArray.contains($0) }
                for addedObject in addedObjects {
                    let chartDataEntry: ChartDataEntry = .init(x: addedObject.time, y: Double(addedObject.count))
                    _ = rawDataSet.addEntryOrdered(chartDataEntry)
                }
            }
            coordinator.cachedRawData = rawData
            changed = true
        }

        if purifiedData != coordinator.cachedPurifiedData {
            if purifiedData.isEmpty {
                purifiedDataSet.removeAll(keepingCapacity: true)
            } else {
                let excludeArray = Set(coordinator.cachedPurifiedData)
                let addedObjects = purifiedData.filter { !excludeArray.contains($0) }
                for addedObject in addedObjects {
                    let chartDataEntry: ChartDataEntry = .init(x: addedObject.time, y: Double(addedObject.count))
                    _ = purifiedDataSet.addEntryOrdered(chartDataEntry)
                }
            }
            coordinator.cachedPurifiedData = purifiedData
            changed = true
        }

        return changed
    }

    func updateMoving(
        scale: RadiationLevelOptions.Scale,
        timeRange: RadiationLevelOptions.TimeRange,
        coordinator: RadiationLevelCoordinatorMovingProtocol
    ) -> Bool {
        guard let data else { return false }

        var needUpdate = false

        var minXValue: Double? = nil
        var maxXValue: Double? = nil

        var isReseted = false
        if coordinator.cachedScale != scale {
            coordinator.cachedScale = scale
            switch scale {
            case .initial:
                isReseted = true
                minXValue = data.xMax - timeRange.timeInterval
                maxXValue = data.xMax
            case let .live(minX, maxX),
                let .position(minX, maxX):
                minXValue = minX
                maxXValue = maxX
                needUpdate = true
            }
        }

        if timeRange != coordinator.cachedTimeRange {
            coordinator.cachedTimeRange = timeRange
            if !isReseted {
                minXValue = data.xMax - timeRange.timeInterval
                maxXValue = data.xMax
            }
        }

        if let minXValue, let maxXValue {
            focusX(minXValue: minXValue, maxXValue: maxXValue)
        }

        return scale.isAutoMoving || needUpdate
    }
}

#Preview {
    let date = Date.now
    let rawData: [RadiationLevelChartDataModel] = [
        .init(count: 25.5, time: date.timeIntervalSince1970),
        .init(count: 5.4, time: date.addingTimeInterval(-20).timeIntervalSince1970),
        .init(count: 15.4, time: date.addingTimeInterval(-30).timeIntervalSince1970),
        .init(count: 5.4, time: date.addingTimeInterval(-40).timeIntervalSince1970)
    ]
    let purifiedData: [RadiationLevelChartDataModel] = [
        .init(count: 5.4, time: date.addingTimeInterval(-50).timeIntervalSince1970),
        .init(count: 25.5, time: date.addingTimeInterval(-120).timeIntervalSince1970),
        .init(count: 15.5, time: date.addingTimeInterval(-55).timeIntervalSince1970)
    ]

    LineChartView.makeRadiationLevelChart(
        rawData: rawData,
        purifiedData: purifiedData,
        timeRange: .minute,
        scale: .initial,
        color: NSUIColor(.accentPurple),
        coordinator: RadiationLevelChartCoordinator(scale: .constant(.initial)),
        indexes: .constant([0, 1, 2]),
        mainSourceForCalculating: true,
        radiationType: .countRate
    )
}

