//
//  RadiationLevelChartRenderer.swift
//  Radiacode
//
//  Created by Matvey Kozin on 28.05.2024.
//

import Foundation
import DGCharts
import CoreGraphics
import SwiftUI

final class RadiationLevelChartRenderer: LineChartRenderer {

    private enum Consts {
        static let pointsPerEntryPair = 2
        static let minPointDistance: CGFloat = 1.0
    }

    private let mainSourceForCalculating: Bool
    private let xBounds = XBounds()

    @Binding private var indexes: [Int]

    init(dataProvider: LineChartDataProvider, animator: Animator, viewPortHandler: ViewPortHandler, indexes: Binding<[Int]>, mainSourceForCalculating: Bool) {
        self._indexes = indexes
        self.mainSourceForCalculating = mainSourceForCalculating
        super.init(dataProvider: dataProvider, animator: animator, viewPortHandler: viewPortHandler)
    }    

    public override func drawExtras(context: CGContext) {}

    public override func drawLinear(context: CGContext, dataSet: LineChartDataSetProtocol) {

        guard let dataProvider = dataProvider else { return }

        let isRawData = dataSet.label == LineChartView.Consts.rawDataSetLabel
        let trans = dataProvider.getTransformer(forAxis: dataSet.axisDependency)
        let valueToPixelMatrix = trans.valueToPixelMatrix
        let phaseY = animator.phaseY

        var points = [CGPoint]()

        if isRawData {
            xBounds.set(chart: dataProvider, dataSet: dataSet, animator: animator)
            points.reserveCapacity(xBounds.range + 1)
            for idx in xBounds {
                guard let entry = dataSet.entryForIndex(idx) else { continue }
                let currentPoint = CGPoint(x: entry.x, y: entry.y * phaseY).applying(valueToPixelMatrix)
                points.append(currentPoint)
            }
        } else {
            if !mainSourceForCalculating {
                points.reserveCapacity(indexes.count + 1)
                for idx in indexes {
                    guard let entry = dataSet.entryForIndex(idx) else { continue }
                    let currentPoint = CGPoint(x: entry.x, y: entry.y * phaseY).applying(valueToPixelMatrix)
                    points.append(currentPoint)
                }
            } else {
                xBounds.set(chart: dataProvider, dataSet: dataSet, animator: animator)
                points.reserveCapacity(xBounds.range + 1)

                var tempIndexes: [Int] = []
                var lastPoint: CGPoint?
                var lastIndex: Int?

                for idx in xBounds {
                    guard let entry = dataSet.entryForIndex(idx) else { continue }
                    let currentPoint = CGPoint(x: entry.x, y: entry.y * phaseY).applying(valueToPixelMatrix)
                    if let previousPoint = lastPoint, abs(currentPoint.x - previousPoint.x) < Consts.minPointDistance {
                        if currentPoint.y < previousPoint.y {
                            points[points.count - 1] = currentPoint
                            lastPoint = currentPoint
                            if lastIndex != nil {
                                tempIndexes[tempIndexes.count - 1] = idx
                            }
                        }
                        continue
                    }
                    tempIndexes.append(idx)
                    lastIndex = idx
                    lastPoint = currentPoint
                    points.append(currentPoint)
                }

                if tempIndexes != indexes {
                    DispatchQueue.main.async {
                        self.indexes = tempIndexes
                    }
                }
            }
        }

        guard points.count > 1 else { return }

        if dataSet.isDrawFilledEnabled {
            let filled = generateFilledPath(points: points)
            if let fill = dataSet.fill {
                drawFilledPath(context: context, path: filled, fill: fill, fillAlpha: dataSet.fillAlpha)
            } else {
                drawFilledPath(context: context, path: filled, fillColor: dataSet.fillColor, fillAlpha: dataSet.fillAlpha)
            }
        }

        context.saveGState()
        context.setLineWidth(dataSet.lineWidth)
        let path = CGMutablePath()
        path.addLines(between: points)
        context.addPath(path)
        context.setStrokeColor(dataSet.color(atIndex: 0).cgColor)
        context.strokePath()
        context.restoreGState()
    }

    private func generateFilledPath(points: [CGPoint]) -> CGPath {
        let filledPath = CGMutablePath()
        guard let firstPoint = points.first, let lastPoint = points.last else { return filledPath }

        let bottomY = viewPortHandler.contentRect.maxY

        // Начинаем путь с первой точки
        filledPath.move(to: firstPoint)
        // Соединяем все точки, чтобы повторить линию графика
        filledPath.addLines(between: points)
        // Добавляем нижнюю точку последней точки графика до нижней границы
        filledPath.addLine(to: CGPoint(x: lastPoint.x, y: bottomY))
        // Замыкаем путь, добавляя линию к первой точке но на нижней границе
        filledPath.addLine(to: CGPoint(x: firstPoint.x, y: bottomY))
        filledPath.closeSubpath()
        return filledPath
    }
}

