import DGCharts

final class TimeOrderedLineDataSet: LineChartDataSet {
    override func entryIndex(entry e: ChartDataEntry) -> Int {
        var lowerBound = 0
        var upperBound = entries.count
        while lowerBound < upperBound {
            let mid = (lowerBound + upperBound) >> 1
            if entries[mid].x < e.x { lowerBound = mid + 1 } else { upperBound = mid }
        }
        guard lowerBound < entries.count, entries[lowerBound].x == e.x else { return -1 }
        var index = lowerBound
        while index < entries.count, entries[index].x == e.x {
            if entries[index] == e { return index }
            index += 1
        }
        return -1
    }
}

