Прочитал все 10 мест. Вот полный diff нормального варианта. Показываю, не применяю — внесу по слову **применить**.

## 1. `ShareSheet.swift` — заменяется целиком на презентер + модификатор

```swift
import SwiftUI
import UIKit

extension View {
    func shareSheet(
        isPresented: Binding<Bool>,
        activityItems: @escaping () -> [Any],
        onComplete: ShareSheetPresenter.Callback? = nil
    ) -> some View {
        background(
            ShareSheetPresenter(isPresented: isPresented, activityItems: activityItems, onComplete: onComplete)
        )
    }

    func shareSheet<Item: Identifiable>(
        item: Binding<Item?>,
        activityItems: @escaping (Item) -> [Any],
        onComplete: ShareSheetPresenter.Callback? = nil
    ) -> some View {
        background(
            ShareSheetPresenter(
                isPresented: Binding(
                    get: { item.wrappedValue != nil },
                    set: { isShown in if !isShown { item.wrappedValue = nil } }
                ),
                activityItems: {
                    guard let value = item.wrappedValue else { return [] }
                    return activityItems(value)
                },
                onComplete: onComplete
            )
        )
    }
}

struct ShareSheetPresenter: UIViewControllerRepresentable {

    typealias Callback = (
        _ activityType: UIActivity.ActivityType?,
        _ completed: Bool,
        _ returnedItems: [Any]?,
        _ error: Error?
    ) -> Void

    @Binding var isPresented: Bool
    let activityItems: () -> [Any]
    var onComplete: Callback?

    func makeUIViewController(context: Context) -> UIViewController { UIViewController() }

    func updateUIViewController(_ uiViewController: UIViewController, context: Context) {
        guard isPresented,
              !context.coordinator.isPresenting,
              uiViewController.presentedViewController == nil else { return }

        let items = activityItems()
        guard !items.isEmpty else {
            DispatchQueue.main.async { isPresented = false }
            return
        }

        context.coordinator.isPresenting = true
        let controller = UIActivityViewController(activityItems: items, applicationActivities: nil)
        controller.excludedActivityTypes = ShareSheetPresenter.excludedActivityTypes
        controller.completionWithItemsHandler = { activityType, completed, returnedItems, error in
            onComplete?(activityType, completed, returnedItems, error)
            context.coordinator.isPresenting = false
            isPresented = false
        }
        if let popover = controller.popoverPresentationController {
            popover.sourceView = uiViewController.view
            popover.sourceRect = CGRect(x: uiViewController.view.bounds.midX, y: uiViewController.view.bounds.maxY, width: 0, height: 0)
            popover.permittedArrowDirections = []
        }
        uiViewController.present(controller, animated: true)
    }

    func makeCoordinator() -> Coordinator { Coordinator() }
    final class Coordinator { var isPresenting = false }
}

private extension ShareSheetPresenter {
    static let excludedActivityTypes: [UIActivity.ActivityType] = [
        // ← тот же список, что был в ShareSheet (без изменений)
    ]
}
```
Старый `struct ShareSheet` и его `#Preview` удаляются (заменяются презентером).

